// Parse the eBay payout CSV. The webhook receives JSON {filename, data} where
// data is the base64-encoded CSV. (This avoids n8n's binary-property handling.)
const body = items[0].json.body || items[0].json;
if (!body.data) {
  throw new Error('Expected JSON body with a base64 `data` field. Got keys: ' + Object.keys(body).join(', '));
}
const text = Buffer.from(body.data, 'base64').toString('utf8');
const lines = text.split(/\r?\n/);
const headerIdx = lines.findIndex(l => l.startsWith('"Transaction creation date"'));
if (headerIdx === -1) throw new Error('Header row not found - upload an eBay payout CSV');

function parseRow(line) {
  const out = [];
  let cur = '', inQ = false;
  for (let i = 0; i < line.length; i++) {
    const c = line[i];
    if (c === '"') { inQ = !inQ; continue; }
    if (c === ',' && !inQ) { out.push(cur); cur = ''; continue; }
    cur += c;
  }
  out.push(cur);
  return out;
}

const header = parseRow(lines[headerIdx]);
const orderCol = header.indexOf('Order number');
const netCol = header.indexOf('Net amount');
const typeCol = header.indexOf('Type');
if (orderCol < 0 || netCol < 0) throw new Error('Required columns not found');
const dateCol = header.indexOf('Transaction creation date');
const descCol = header.indexOf('Description');
const payoutDateCol = header.indexOf('Payout date');
const payoutIdCol = header.indexOf('Payout ID');
const payoutMethodCol = header.indexOf('Payout method');

// Payout metadata (constant across all rows) - extracted from the first valid data row.
let payout = null;
for (let i = headerIdx + 1; i < lines.length && !payout; i++) {
  const r = parseRow(lines[i]);
  const pid = payoutIdCol >= 0 ? (r[payoutIdCol] || '').trim() : '';
  if (pid && pid !== '--') {
    payout = {
      id: pid,
      date: payoutDateCol >= 0 ? (r[payoutDateCol] || '').trim() : '',
      dateUnix: 0,
      method: payoutMethodCol >= 0 ? (r[payoutMethodCol] || '').trim() : '',
    };
    const ts = Date.parse(payout.date);
    if (Number.isFinite(ts)) payout.dateUnix = Math.floor(ts / 1000);
  }
}

const groups = new Map();
for (let i = headerIdx + 1; i < lines.length; i++) {
  const row = parseRow(lines[i]);
  const order = (row[orderCol] || '').trim();
  const netRaw = (row[netCol] || '').replace(/,/g, '').trim();
  if (!order || order === '--') continue;
  if (!netRaw || netRaw === '--') continue;
  const net = Number(netRaw);
  if (!Number.isFinite(net)) continue;
  const g = groups.get(order) || { orderNumber: order, ebayNet: 0, rows: 0, types: new Set(), lines: [] };
  g.ebayNet += net;
  g.rows += 1;
  const type = (row[typeCol] || '').trim();
  g.types.add(type);
  g.lines.push({
    date: dateCol >= 0 ? (row[dateCol] || '').trim() : '',
    type,
    net: Math.round(net * 100) / 100,
    description: descCol >= 0 ? (row[descCol] || '').trim() : '',
  });
  groups.set(order, g);
}

return Array.from(groups.values()).map(g => ({
  json: { orderNumber: g.orderNumber, ebayNet: Math.round(g.ebayNet * 100) / 100, rows: g.rows, types: Array.from(g.types), lines: g.lines, _payout: payout }
}));

// Match each Find SO response back to its eBay context via ref_client. Emit MISSING
// for any eBay orders Dolibarr didn't return.
const ebayMap = new Map();
for (const e of $('Parse and Group').all()) {
  ebayMap.set(e.json.orderNumber, e.json);
}

const seen = new Set();
const out = [];

for (const it of items) {
  const so = it.json;
  if (!so || !so.id || !so.ref_client) continue;
  const ebay = ebayMap.get(so.ref_client);
  if (!ebay) continue;
  seen.add(so.ref_client);
  out.push({ json: {
    orderNumber: ebay.orderNumber,
    ebayNet:     ebay.ebayNet,
    ebayRows:    ebay.rows,
    ebayTypes:   ebay.types,
    ebayLines:   ebay.lines,
    dolOrderId:  so.id,
    dolOrderRef: so.ref,
    status:      'pending',
  }});
}

for (const [orderNumber, ebay] of ebayMap) {
  if (seen.has(orderNumber)) continue;
  out.push({ json: {
    orderNumber: ebay.orderNumber,
    ebayNet:     ebay.ebayNet,
    ebayRows:    ebay.rows,
    ebayTypes:   ebay.types,
    ebayLines:   ebay.lines,
    dolOrderId:  null,
    dolOrderRef: null,
    dolNet:      0,
    diff:        ebay.ebayNet,
    invoices:    [],
    status:      'MISSING_IN_DOLIBARR',
  }});
}

return out;

// Single aggregator: walks every Dolibarr invoice/CN that came in via the
// ref_client query, groups by ref_client, sums total_ht. Then iterates over
// every 'pending' (found-in-Dolibarr) eBay order from Classify to produce one
// output row per order with status MATCH / MISMATCH / NO_LINKED_INVOICES.

const pending = $('Classify (found/missing)').all()
  .map(x => x.json)
  .filter(x => x.status === 'pending');

// Build {orderNumber: [docs...]} from incoming items (auto-split by n8n).
const byOrder = new Map();
for (const it of items) {
  const d = it.json;
  if (!d || !d.id || !d.ref_client) continue;
  const isCredit = String(d.type) === '2';
  const amt = Number(d.total_ht || 0); // Dolibarr already stores CN total_ht as negative.
  const list = byOrder.get(d.ref_client) || [];
  list.push({ id: d.id, ref: d.ref, type: isCredit ? 'credit_note' : 'invoice', totalHt: Math.round(amt * 100) / 100 });
  byOrder.set(d.ref_client, list);
}

const out = [];
for (const ctx of pending) {
  const docs = byOrder.get(ctx.orderNumber) || [];
  // Only invoices (type=0) feed dolNet. Applied credit notes already reduce the
  // invoice's total_ht via a discount line, so counting them again would
  // double-count. CNs are kept in `docs` for UI visibility.
  const invoices = docs.filter(d => d.type === 'invoice');
  let dolNet = 0;
  for (const d of invoices) dolNet += d.totalHt;
  dolNet = Math.round(dolNet * 100) / 100;
  const diff = Math.round((ctx.ebayNet - dolNet) * 100) / 100;
  let status;
  if (invoices.length === 0) status = 'NO_LINKED_INVOICES';
  else if (Math.abs(diff) > 0.01) status = 'MISMATCH';
  else status = 'MATCH';
  out.push({ json: {
    orderNumber: ctx.orderNumber,
    ebayNet:     ctx.ebayNet,
    ebayRows:    ctx.ebayRows,
    ebayTypes:   ctx.ebayTypes,
    ebayLines:   ctx.ebayLines,
    dolOrderId:  ctx.dolOrderId,
    dolOrderRef: ctx.dolOrderRef,
    dolNet,
    diff,
    invoices:    docs,
    status,
  }});
}
return out;

// Final summary + filtered lists + payout metadata for downstream Pay calls.
const all = items.map(i => i.json);
const matches  = all.filter(r => r.status === 'MATCH');
const mismatch = all.filter(r => r.status === 'MISMATCH');
const missing  = all.filter(r => r.status === 'MISSING_IN_DOLIBARR');
const noInv    = all.filter(r => r.status === 'NO_LINKED_INVOICES');
const payout   = $('Parse and Group').first().json._payout || null;
return [{
  json: {
    summary: {
      ordersCompared:    all.length,
      matches:           matches.length,
      mismatches:        mismatch.length,
      missingInDolibarr: missing.length,
      noLinkedInvoices:  noInv.length,
    },
    payout,
    discrepancies: [...mismatch, ...missing, ...noInv],
    matches,
  }
}];
